// Extract YouTube video ID from URL and pass through record_id
const input = $input.first().json;
const url = input.youtube_url || '';

// Support all YouTube URL formats
const patterns = [
  /[?&]v=([a-zA-Z0-9_-]{11})/,
  /youtu\.be\/([a-zA-Z0-9_-]{11})/,
  /embed\/([a-zA-Z0-9_-]{11})/,
  /shorts\/([a-zA-Z0-9_-]{11})/
];

let video_id = null;
for (const pattern of patterns) {
  const match = url.match(pattern);
  if (match) {
    video_id = match[1];
    break;
  }
}

if (!video_id) {
  throw new Error('Could not extract YouTube video ID from URL: ' + url);
}

return [{
  json: {
    record_id: input.record_id,
    youtube_url: url,
    video_id
  }
}];

// Parse YouTube timedtext JSON3 format and extract plain text
// Preserves record_id and video_id from previous node
const prev = $('Extract Video ID').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  // Timedtext JSON3 format: { events: [{ segs: [{ utf8: '...' }] }] }
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    // Clean up whitespace and newlines
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error — has_content stays false, falls through to fallback
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_asr'
  }
}];

// Parse manual captions (same format as ASR, without kind=asr)
const prev = $('Parse Timedtext ASR').first().json;
const response = $input.first().json;

let transcript = '';
let has_content = false;

try {
  if (response.events && Array.isArray(response.events) && response.events.length > 0) {
    const parts = [];
    for (const event of response.events) {
      if (event.segs && Array.isArray(event.segs)) {
        for (const seg of event.segs) {
          if (seg.utf8 && seg.utf8.trim()) {
            parts.push(seg.utf8);
          }
        }
      }
    }
    const raw = parts.join('');
    transcript = raw.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
    has_content = transcript.length > 50;
  }
} catch (e) {
  // Parse error
}

return [{
  json: {
    record_id: prev.record_id,
    youtube_url: prev.youtube_url,
    video_id: prev.video_id,
    transcript,
    has_content,
    method: 'timedtext_manual'
  }
}];

// AssemblyAI fallback transcription — Phase 2
// Runs when both YouTube timedtext paths (ASR + manual) return no content.
// AssemblyAI accepts YouTube URLs natively — no audio download or Worker needed.
//
// SETUP REQUIRED before this path activates:
//   1. Sign up at https://www.assemblyai.com and get your API key
//   2. In n8n: Settings → Variables → Add: ASSEMBLYAI_API_KEY = <your key>
//
// Cost: ~$0.37/hour of audio (pay-per-use, no monthly minimum)
// Free tier available for testing.

const prev = $('Parse Timedtext Manual').first().json;
const youtubeUrl = prev.youtube_url;
const recordId = prev.record_id;

const API_KEY = $vars.ASSEMBLYAI_API_KEY;
if (!API_KEY) {
  return [{ json: {
    record_id: recordId,
    transcript: '',
    method: 'none',
    success: false,
    error: 'AssemblyAI API key not configured. Add ASSEMBLYAI_API_KEY to n8n Variables (Settings → Variables).',
  }}];
}

const BASE = 'https://api.assemblyai.com/v2';
const headers = { 'Authorization': API_KEY, 'Content-Type': 'application/json' };

// 1. Submit transcription job — AssemblyAI accepts YouTube URLs directly
let submission;
try {
  submission = await $helpers.httpRequest({
    method: 'POST',
    url: `${BASE}/transcript`,
    headers,
    body: JSON.stringify({ audio_url: youtubeUrl }),
  });
} catch (err) {
  return [{ json: {
    record_id: recordId,
    transcript: '',
    method: 'none',
    success: false,
    error: 'AssemblyAI submission error: ' + err.message,
  }}];
}

if (!submission.id) {
  return [{ json: {
    record_id: recordId,
    transcript: '',
    method: 'none',
    success: false,
    error: 'AssemblyAI returned no job ID. Response: ' + JSON.stringify(submission),
  }}];
}

const jobId = submission.id;

// 2. Poll until complete or error (max 5 min = 30 × 10s)
for (let attempt = 0; attempt < 30; attempt++) {
  await new Promise(r => setTimeout(r, 10000));

  let result;
  try {
    result = await $helpers.httpRequest({
      method: 'GET',
      url: `${BASE}/transcript/${jobId}`,
      headers,
    });
  } catch (err) {
    // Transient poll error — continue
    continue;
  }

  if (result.status === 'completed') {
    return [{ json: {
      record_id: recordId,
      transcript: result.text || '',
      method: 'assemblyai',
      success: true,
      error: '',
    }}];
  }

  if (result.status === 'error') {
    return [{ json: {
      record_id: recordId,
      transcript: '',
      method: 'none',
      success: false,
      error: 'AssemblyAI transcription failed: ' + (result.error || 'unknown error'),
    }}];
  }
  // status is 'queued' or 'processing' — keep polling
}

// Timeout after 5 minutes
return [{ json: {
  record_id: recordId,
  transcript: '',
  method: 'none',
  success: false,
  error: 'AssemblyAI timed out after 5 minutes. Video may be too long or API queue is busy.',
}}];
